solution: class Solution {
public:
    int strangePrinter(string s) {
        int n = s.size();
        if (n == 0) return 0;
        vector<vector<int>> dp(n, vector<int>(n, 0));
        for (int i = 0; i < n; ++i) dp[i][i] = 1;
        for (int len = 2; len <= n; ++len) {
            for (int l = 0; l <= n - len; ++l) {
                int r = l + len - 1;
                dp[l][r] = dp[l][r - 1] + 1;
                for (int k = l; k < r; ++k) {
                    if (s[k] == s[r]) {
                        dp[l][r] = min(dp[l][r], dp[l][k] + dp[k + 1][r - 1]);
                    }
                }
            }
        }
        return dp[0][n - 1];
    }
};
